#include <bits/stdc++.h>
using namespace std;

struct ListNode {
    int val;
    ListNode *next;
    ListNode(int x) : val(x), next(nullptr) {}
    ListNode() : val(0), next(nullptr) {}
};

class Solution {
public:
    ListNode* addOne(ListNode* head) {
        int carry = 1;
        ListNode* node = head;
        ListNode* prev = nullptr;
        while (node != nullptr && carry) {
            int total = node->val + carry;
            node->val = total % 10;
            carry = total / 10;
            prev = node;
            node = node->next;
        }
        if (carry) {
            prev->next = new ListNode(carry);
        }
        return head;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> vals(n);
    for (int i = 0; i < n; ++i) cin >> vals[i];
    // build linked list in given order (reverse representation)
    ListNode dummy;
    ListNode* cur = &dummy;
    for (int v : vals) {
        cur->next = new ListNode(v);
        cur = cur->next;
    }
    ListNode* head = dummy.next;
    Solution sol;
    ListNode* new_head = sol.addOne(head);
    // output
    bool first = true;
    while (new_head) {
        if (!first) cout << ' ';
        first = false;
        cout << new_head->val;
        new_head = new_head->next;
    }
    cout << "\n";
    return 0;
}
